import{_ as o,o as t,c as n,ak as a}from"./chunks/framework.tZEZYUNo.js";const u=JSON.parse('{"title":"Documentation maintenance","description":"","frontmatter":{},"headers":[],"relativePath":"maintenance.md","filePath":"maintenance.md"}'),i={name:"maintenance.md"};function s(r,e,d,c,l,h){return t(),n("div",null,[...e[0]||(e[0]=[a('<h1 id="documentation-maintenance" tabindex="-1">Documentation maintenance <a class="header-anchor" href="#documentation-maintenance" aria-label="Permalink to “Documentation maintenance”">​</a></h1><h2 id="when-to-update-documentation" tabindex="-1">When to update documentation <a class="header-anchor" href="#when-to-update-documentation" aria-label="Permalink to “When to update documentation”">​</a></h2><p>Update docs <strong>in the same pull request</strong> as the behavior change when you:</p><ul><li>Add or remove Nx targets or change <code>nx.json</code> defaults</li><li>Change CI workflows (affected detection, lint commands, release steps)</li><li>Add a new plugin or theme (include <code>docs/index.md</code> and labeler entries)</li><li>Change tagging, Composer, or deployment assumptions</li></ul><h2 id="ownership" tabindex="-1">Ownership <a class="header-anchor" href="#ownership" aria-label="Permalink to “Ownership”">​</a></h2><ul><li><strong>Contributors</strong> are responsible for keeping package-local docs (<code>plugins/&lt;slug&gt;/docs/</code>, <code>themes/&lt;slug&gt;/docs/</code>) accurate.</li><li><strong>Maintainers / platform</strong> own root workflows, GitHub Pages, and secrets (PATs for mirrors if used).</li><li><strong>No silent TODOs</strong> — If something is blocked, add a short note with <strong>next step</strong> and <strong>who</strong> should unblock (team name or role), or create an issue and link it.</li></ul><h2 id="how-to-edit-the-docs-site" tabindex="-1">How to edit the docs site <a class="header-anchor" href="#how-to-edit-the-docs-site" aria-label="Permalink to “How to edit the docs site”">​</a></h2><ol><li><strong>Monorepo guides</strong> — Edit Markdown in <code>docs/*.md</code> (this folder).</li><li><strong>Package docs</strong> — Edit files under <code>plugins/.../docs/</code> or <code>themes/.../docs/</code>; run <code>pnpm docs:dev</code> to preview.</li><li><strong>Navigation</strong> — New top-level pages must be registered in <code>docs/.vitepress/config.mts</code> (sidebar and nav).</li><li><strong>Generated output</strong> — Never commit hand-edits under <code>docs/content/</code>; it is produced by <code>tools/sync-docs.mjs</code>.</li></ol><h2 id="review-checklist-for-doc-prs" tabindex="-1">Review checklist for doc PRs <a class="header-anchor" href="#review-checklist-for-doc-prs" aria-label="Permalink to “Review checklist for doc PRs”">​</a></h2><ul><li>[ ] Links to GitHub paths use the correct branch or are relative where possible</li><li>[ ] Commands tested from a clean clone or noted if environment-specific</li><li>[ ] Versioning / release sections match current workflow YAML</li><li>[ ] No personal machine paths (for example <code>/Users/...</code>)</li></ul>',10)])])}const p=o(i,[["render",s]]);export{u as __pageData,p as default};
